import { readFileSync } from 'node:fs';
const footer = readFileSync('apps/liora/src/tui/components/chrome/footer.ts','utf8');
const tele = readFileSync('apps/liora/src/cli/telemetry.ts','utf8');
const status = readFileSync('apps/liora/src/tui/components/messages/status-panel.ts','utf8');
const fails=[];
if (!footer.includes('formatZdrFooterBadge')) fails.push('footer');
if (!footer.includes("'zdr'")) fails.push('zdr-label');
if (!tele.includes('config.telemetry === true')) fails.push('opt-in');
if (!status.includes('ZDR-friendly local')) fails.push('status');
if (fails.length) { console.error(fails.join(',')); process.exit(1);} console.log('zdr-footer-source-ok');
